        start_npc = 'Moogle',
        start_zone = 'Home Nation Mog House',
        start_pos = nil,
        description = 'Mission Orders: Your local Mog House moogle says that the time has come for moogle and adventurer to work as one. You must head to the stone circle in La Theine Plateau. Get a move on!',
