        next = {'Ghatsad\'s Quandary'},
        requirements = nil,
        walkthrough = '1. Head to the palace at Aht Urghan Whitegate (L-9) HP-#2 and click the gate Imperial Whitegate for a cutscene.\n2. Travel to Caedarva Mire Map 4 (Hediva Isle).\n   - Unity Warp (Lv. 135, Shedu) to Caedarva Mire is the fastest way\n     - The Shedu warp requires either Captain Mercenary Rank or a [Key Item] Remnants Permit from Salvage.\n   - Alternatively, take the Runic Portal to the Nyzul Isle Staging Point in Alzadaal Undersea Ruins.\n     - From the Nyzul Isle Staging Point, walk west-northwest towards (H-8) and use the teleporter, marked D on map 5.\n     - After you zone, take the teleporter on your left marked as J on map 4.\n     - Walk north and zone to Caedarva Mire Map 4 (Hediva Island).\n   - If you don\'t have the Nyzul Isle or Unity warp, see the Nyzul Isle Staging Point page for instructions to walk there.\n3. When you\'re ready, go north east through a slightly hidden path and touch the Savage Scars at (I-6) beside the Engraved Tablet for a cutscene.\n   - The upcoming fight is soloable at iLvl 119 with medium difficulty depending on your job and available trusts.\n     - Summon your trust team in advance so your WHM trust gets Protectra V and Shellra V up on foes along the way.\n4. Touch the Savage Scars again for a battle against 1x Arisen Soulflayer and 3x Descended Winebibber (Clot Slimes). 15 minute time limit.\n   - The Descended Winebibber must be defeated in order to win.\n     - Beware of Fluid Toss, a powerful  TP move.\n   - Uran-Mafran will assist in battle. They are a BLM and will melee with a club if the enemy is within melee range, but will otherwise cast spells from his position.\n     - Uran-Mafran stays at range unless he takes hate.\n     - If Uran-Mafran is KOed then the fight is lost. They may be cured like any other NPC.\n5. Select the Savage Scars again for a cutscene.\n6. Head back to the palace at Aht Urghan Whitegate (L-9) and check the "Imperial Whitegate" door for a cutscene.\n   - You will obtain [Key Item] Mnejing\'s receiver as a reward allowing you to hear Besieged messages outside of Aht Urghan.\n   - Completing the quest "A Stygian Pact" will unlock an extra dialogue option with regards to Odin.',
        notes = '1. You can now open up access to new RoE Quests 4 objectives.\n   - See the NPC Elijah in Upper Jeuno near Home Point #1 for more information.',
    },
    ['Run, Excenmille, Run!'] = {
        id = 228,
        start_npc = 'Halver',
        start_zone = 'Chateau d\'Oraguille',
        start_pos = nil,
        description = 'Mission Orders: The ball was a rousing success. However, there have been reports dispatched to the north. Follow Prince Trion to where Rahal waits in the Royal Knights\' Quarters.',
        reward = 'Hi-Elixir Tank',
        fame = nil,
        fame_level = nil,
        title = 'None',
        repeatable = 'No',
        previous = {'Curilla Unleashed'},
        next = {'Of Knights and Orcs'},
        requirements = nil,
        walkthrough = '1. Speak with Halver for a cutscene to begin the mission.\n2. Speak with Rahal in the Royal Knight\'s quarters for another cutscene.\n3. Head to Beaucedine Glacier.\n   - The quickest way is via Survival Guide (Fauregandi) warp.\n4. Touch the Ferric Stench (H-8) next to the East side of the tower to begin a confrontation with:\n   - Orcish Atlatl (WAR)\n   - Orcish Axeman (BST)\n   - Orcish Praetor (WAR)\n   - Harnessed Smilodon (WAR)\n     - Orc NM\'s can use their job\'s respective SP abilities.\n     - All foes are susceptible to sleep.\n     - You will receive [Key Item]Carmine Swallows\' map after the fight.\n5. Afterwards, touch the Ferric Stench again for a cutscene.\n6. Touch the Point of Interest at the lowest left corner intersection of (J-6)/(I-6) for a final cutscene.\n   - This is located next to the Mirror Pond along the way to Fei\'Yin past the Gargantua tower.\n   - Fastest to take the Unity warp 128 to Fei\'Yin and zone out into Beaucedine Glacier.\n   - You will receive Hi-Elixir Tank after the cutscene.',
        notes = nil,
    },
    ['Skokkr Undrborn\'s Temptation'] = {
        id = 530,
        start_npc = 'Glowing Hearth',
        start_zone = 'Eastern Adoulin',
        start_pos = 'H-6',
        description = 'Mission Orders: Your invitation to the Silver Knife has arrived. The dvergr Skokkr Undrborn is supposedly there, potentially in the guise of a humanoid. Ask around for information.',
        reward = '20,000 Gil',
        fame = nil,
        fame_level = nil,
        title = nil,
        repeatable = 'No',
        previous = {'Phantasmic Heroes'},
        next = {'The Prime Weapons'},
        requirements = nil,
        walkthrough = '1. Speak with Glowing Hearth in Eastern Adoulin (H-6) near Homepoint #1 for a cutscene.\n   - During the cutscene, you will be transported inside of the Silver Knife zone.\n2. Speak with Oscarnot inside for a cutscene.\n   - If the bidding closes for the Auria Collection you will need to talk to Zemerine before talking to Gama-Shama.\n3. Speak with Gama-Shama in the Silver Knife. He will mention how it was hard to procure his Esthete\'s Masque and how he obtained his attire from Runje Desaali.\n4. Speak to Runje Desaali in Eastern Adoulin (J-10) until she shows you the Esthete\'s Masque and hint at wanting some specific equipment that is in high demand.\n   - Quickest from the Castle Adoulin gates waypoint.\n5. Make sure you get the dialogue about the mask before you trade or you will need a new item.\n6. Trade her an Item Level 106 or 115 Wildskeeper Reive Weapon, Armor, or Rare/Ex Accessory. She will give you 4000 or 6000 Bayld depending on the item and the cutscene will continue.\n   - It may be worth looking to see if you have a Kupon AW-WK or [Key Item] Mog Kupon AW-WK already, before participating in a Wildskeeper Reive.\n   - Records of Eminence NPCs can also trade all 6 Wildkeeper Reive Key Items for a weapon.\n7. After trading in any applicable item, she then unlocks new shop items. Ask her What does Geosuke recommend?.\n8. Buy a Esthete\'s Masque, Esthete\'s Coat and Esthete\'s Hose from Runje Desaali.\n   - Each piece is 30,000 Bayld. You need all 3 for 90,000 Bayld to continue.\n9. Return to the Silver Knife and speak to Zemerine with all items equipped or the set as a Lockstyle for a cutscene.\n   - Other lockstyles cannot be used.\n   - If this cutscene does not play, attempt the next step by removing the equipment and talking to Oscarnot. Discussion Page\n10. Unequip the items or disable your lockstyle, then speak with Oscarnot for another cutscene.\n11. Speak with Glowing Hearth outside of the Silver Knife in Eastern Adoulin for a cutscene and reward.',
        notes = nil,
    },
    ['Sky, Moon, Incantrix'] = {
        id = 380,
        start_npc = 'Reikuu',
        start_zone = 'Reisenjima',
        start_pos = 'K-8',
        description = 'Mission Orders: Gessho and the Far Eastern Yagudo Reikuu believe that the World Eater Egg will give birth to an avatar that must be put down with extreme prejudice. They aim to reunite with their Middle Lands brethren and  seek information on the black sword. You are to go procure it from the Goblin Incantrix.',
        reward = '20,000 Gil',
        fame = nil,
        fame_level = nil,
        title = nil,
        repeatable = 'No',
        previous = {'The Sea Sage'},
        next = {'Nii\'s Last Stand'},
        requirements = nil,
        walkthrough = '1. Note:  Bring 3 Hoptoad and an Eastern Ginger to save time.\n2. Speak with Reikuu (K-8) near Ethereal Ingress #6 in Reisenjima for a cutscene to begin the mission.\n3. Head to Ethereal Ingress #10 and speak with Incantrix for another cutscene.\n   - You must choose the option "No, of course not" in order to continue with the quest.\n4. Head to (H-6) between Ethereal Ingress #3 & #5 in Reisenjima and examine Suspicious Overgrowth for a cutscene.\n   - Gessho will ask for 3 Hoptoad and an Eastern Ginger.\n     - Hoptoad are obtained by fishing in Reisenjima, off the bridge near Ethereal Ingress #2 with a Fly Lure or Lufaise Fly and any rod.\n     - The bite rate may vary depending on your fishing rod and whether you have [Key Item] Frog Fishing.\n     - With Lu Shang\'s F. Rod or Ebisu Fishing Rod and sufficient skill, the bite rate is nearly 100%, even without the KI.\n     - Eastern Ginger can be harvested in Reisenjima (touching Grimslight requires [Key Item] Reaper), harvested in Bhaflau Thickets or found in treasure caskets in Reisenjima.\n     - [Key Item] Reaper is sold by Shiftrix (F-12) for 50 Silt.\n5. Trade the items to the Suspicious Overgrowth for a cutscene.\n6. Return to Reikuu (K-8) near Ethereal Ingress #6 for the final cutscene and your reward.',
        notes = nil,
    },
    ['Star Onion Fortune'] = {
        id = 168,
        start_npc = 'Tosuka-Porika',
        start_zone = 'Windurst Waters Map 1',
        start_pos = 'G-8',
        description = 'Mission Orders: The doll you retrieved from Giddeus is no more than a child\'s plaything. Return it to its owner near a warehouse near the waterfront in Windurst.',
        reward = 'Oden  x12',
        fame = nil,
        fame_level = nil,
        title = nil,
        repeatable = 'No',
        previous = {'Zhuu Buxu\'s Gambit'},
        next = {'The Doll Whisperer'},
        requirements = nil,
        walkthrough = '1. Speak to Tosuka-Porika again for a cutscene. Zoning is not required after the previous mission.\n2. Speak to Kohlo-Lakolo in Port Windurst (G-5) (HP #1) behind Warehouse 1 for a cutscene.\n   - (Optional): Talking to Kohlo-Lakolo again will give you a hint.\n   - (Optional): Speaking to Shanruru gives an additional cutscene.\n3. Open up your Temporary Key Item menu and examine the [Key Item] Piece of evidence in your Temporary Key Items to see a cipher.\n4. Speak to Kohlo-Lakolo for another cutscene. He will ask if you deciphered the evidence, say yup.\n   - Even though you probably didn\'t, it seems your character did.\n     - For anyone curious, the encrypted message uses a simple caesar cipher and says: "I require the special egg and a very strong individual. First comes the egg."\n5. Travel to the The Boyahda Tree and visit any of the three Muggy Air sites at (D-5), (H-6), and (H-9) Map 1, bottom floor.\n   - You may take Unity Warp (Level 125) to The Boyahda Tree. Once there, turn around to zone to Map 1.\n   - May need to travel to all 3 spots as one activates the cutscene.\n6. Touching the active site will immediately spawn the Templar Crawler NM. The active site will have a white glowing animation.\nNot all sites will be active, so keep looking at the different positions.\n   - Deals enhanced damage via Poison Breath.\n   - Appears to gain an additional Protect buff after using Cocoon.\n7. Each party member will receive a [Key Item] Sublime lucky egg upon defeating the NM.\n8. Return to Kohlo-Lakolo for a cutscene and your reward.',
        notes = nil,
    },
    ['Tateeya\'s Worries'] = {
        id = 338,
        start_npc = 'Tateeya',
        start_zone = 'Aht Urhgan Whitegate',
        start_pos = 'I-7',
        description = 'Mission Orders: Ghatsad\'s search continues apace, and he is on the verge of a breakthrough into the mysteries of Olduum. He has made a startling discovery and is a bit on edge. Ask his apprentices for more information.',
        reward = 'Thunder Hammer',
        fame = nil,
        fame_level = nil,
        title = 'Treasure of Olduum',
        repeatable = 'No',
        previous = {'The Revelation'},
        next = {'The Seagull Phratrie'},
        requirements = nil,
        walkthrough = '1. Speak with Tateeya in the Automaton Workshop (I-7) in Aht Urhgan Whitegate for a cutscene to begin the Mission.\n2. Speak with Ghatsad for another cutscene.\n   - Being in the middle of No Strings Attached may prevent you from continuing this Quest.\n3. Head to the Jade Sepulcher.\n   - Fastest way is by Home Point #1 to Bhaflau Thickets Map 2.\n   - Another way is to go to Mamool Ja Staging Point to Bhaflau Thickets Map 2 and head North.\n4. Examine the Ornamental Door for a cutscene.\n5. Examine the Ornamental Door again to enter the BCNM fight "Tateeya\'s Worries" against:\n   - Drakeweaver Hageel Ja (PLD) - 60k HP\n   - Riftweaver Pomaal Ja (BLU) - 60k HP\n   - Fistweaver Mufaal Ja (Sahagin MNK) - 60k HP\n   - Glyphweaver Sikool Ja (BLM). - 100k HP\n     - Casts Stun, Thunder V, Thunder VI, Ionohelix II, Thundaja.\n     - These will not do much harm to a player in MDT/Magic Evasion gear, but will deal solid damage against trusts.\n   - Trusts may be used in the fight.\n     - This is a true BCNM so there is room to buff and summon trusts before engaging.\n   - Glyphweaver Sikool Ja\'s weapon must be broken to win the fight, otherwise he\'ll remain at 1%.\n     - To do this you need to weaponskill as the NM is doing a melee attack or very shortly after.\n     - If the Sikool hits 1% you will do 0 damage, consider bringing some forms of Regain or Meditate either from main or subjob as appropriate.\n   - All foes utilize their  1-hour abilities.\n   - All foes can be silenced\n     - Glyphweaver Sikool Ja will be resistant, likely require Immunobreaks.\n   - All mobs can be slept\n     - Drakeweaver Hageel Ja possesses the resist sleep trait.\n     - Glyphweaver Sikool Ja is resistant to sleep and will require Immunobreaks.\n     - Fistweaver Mufaal Ja was slept twice by M30 RDM\n6. Head back to Aht Urhgan Whitegate and examine Imperial Whitegate for the final cutscene and the Thunder Hammer .\n   - Note: Do not discard the Thunder Hammer .  You will need it for a later Mission.',
        notes = nil,
    },
    ['The Brygid Cup'] = {
