    ['The Cardians\' Duty'] = {
        id = 146,
        start_npc = 'Shantotto',
        start_zone = 'Windurst Walls',
        start_pos = 'K-7',
        description = 'Mission Orders: Shantotto is lamenting that many seem to have memory issues of late. She thinks a sinister force is behind this. Aid Kupipi in getting to the bottom of it.',
