        next = {'Zhuu Buxu\'s Gambit'},
        requirements = nil,
        walkthrough = '1. Speak to Shantotto in her manor at Windurst Walls (K-7) for a cutscene, no zoning required from the previous Mission.\n2. Speak to Kupipi in Heavens Tower for a cutscene.\n   - (Optional): Speak to Sassa-Kotassa, Sheelala, and Habida-Jubida in the lobby area once again, they will offer hints to your next destination.\n3. Head to East Sarutabaruta (J-8) and check the Disturbed Earth for a cutscene. It is South of the Tower and close to the canyon\'s wall.\n   - Fastest route is the Unity Warp (Level 99) to East Sarutabaruta or alternatively the Survival Guide to Inner Horutoto Ruins.\n4. Clicking the Disturbed Earth will spawn a battle with a Yagudo Vicar (WHM), Yagudo Centurion (BLM), and two Yagudo Underlings (NIN, MNK).\n   - You have 15 minutes to complete this confrontation.\n   - Each enemy NM has approximately 30k HP and access to their job\'s SP Ability.\n   - King of Spades (PLD) assists the players, and you will automatically lose the fight if he dies.\n     - All NM\'s will initially focus King of Spades, and he will use Invincible once at lower HP.\n   - AA TT Trust Sleepga will work on the NMs.\n5. Check the Disturbed Earth once more after the battle for a cutscene.\n6. Return to Heavens Tower and speak with Kupipi for a final cutscene and your reward.',
        notes = nil,
    },
    ['The Destiny Destroyers'] = {
        id = 128,
        start_npc = 'Gumbah',
        start_zone = 'Bastok Mines',
        start_pos = 'J-7',
        description = 'The black-clad Goblin seems to have given up on Raebrimm, but now\'s no time to rest on your laurels. The Mythril Musketeers are hot on the trail; head to Korroloka Tunnel to assist them.',
        reward = 'Maat\'s Mix \nOm. Sandwich  x12',
